use std::io;
use std::str::FromStr;

fn main() {
    let mut buf = String::new();
    io::stdin().read_line(&mut buf).unwrap();
    let w = i32::from_str(buf.trim()).unwrap();
    println!(
        "{}",
        match (w - 2) > 0 && (w - 2) % 2 == 0 {
            true => "YES",
            false => "NO",
        }
    )
}
